<template><div v-if="open" class="sc-design-dialog-backdrop" @mousedown.self="$emit('close')" @keydown.esc="$emit('close')"><section ref="dialog" :class="['sc-dialog', panelClass]" role="dialog" aria-modal="true" :aria-labelledby="titleId" tabindex="-1"><header><h2 :id="titleId">{{ title }}</h2><ScIconButton :label="closeLabel" @click="$emit('close')"><ScIcon name="close" /></ScIconButton></header><slot /><footer v-if="$slots.actions" class="sc-action-group"><slot name="actions" /></footer></section></div></template>
<script setup lang="ts">import { nextTick,ref,useId,watch } from 'vue'; import ScIcon from './ScIcon.vue'; import ScIconButton from './ScIconButton.vue'; const props=withDefaults(defineProps<{open:boolean;title:string;closeLabel?:string;panelClass?:string}>(),{closeLabel:'关闭',panelClass:''}); defineEmits<{close:[]}>(); const dialog=ref<HTMLElement|null>(null); const titleId=`sc-dialog-${useId()}`; watch(()=>props.open,async(open)=>{if(open){await nextTick(); const initial=dialog.value?.querySelector<HTMLElement>('[autofocus], [data-dialog-primary]'); (initial||dialog.value)?.focus();}});</script>
<style scoped>.sc-design-dialog-backdrop{position:fixed;inset:0;z-index:1000;display:grid;place-items:center;padding:var(--sc-product-page-gutter);background:var(--sc-app-overlay)}.sc-dialog{width:min(100%,560px);max-height:calc(100vh - 2 * var(--sc-product-page-gutter));overflow:auto}.sc-dialog>header{display:flex;align-items:center;justify-content:space-between;gap:var(--sc-product-space-2)}.sc-dialog h2{margin:0;font-size:var(--sc-product-text-section)}.sc-dialog>footer{justify-content:flex-end;margin-top:var(--sc-product-space-3)}</style>
